CREATE TRIGGER LG_STFICHE_INS_099_02 ON LG_099_02_STFICHE
FOR INSERT
AS
DECLARE @CLREF      INT
DECLARE @TRCODE     SMALLINT
DECLARE @NETTOTAL   FLOAT
DECLARE @REPORTRATE FLOAT
DECLARE @BILLED     SMALLINT
DECLARE @STATUS     SMALLINT
DECLARE @CANCELLED  SMALLINT
DECLARE @AFFECTCOLLTRL SMALLINT
DECLARE @AFFECTRISK SMALLINT
DECLARE @FROMORDWITHPAY SMALLINT
SELECT @CLREF = I.CLIENTREF,
       @TRCODE = I.TRCODE,
       @NETTOTAL = I.NETTOTAL,
       @REPORTRATE = I.REPORTRATE,
       @BILLED = I.BILLED,
       @STATUS = I.STATUS,
       @CANCELLED = I.CANCELLED,
       @AFFECTCOLLTRL = I.AFFECTCOLLATRL,
       @AFFECTRISK = I.AFFECTRISK,
       @FROMORDWITHPAY = I.FROMORDWITHPAY   FROM INSERTED I
IF (ISNULL(@AFFECTRISK,0)=0) AND (ISNULL(@CANCELLED,0)=0) AND (ISNULL(@FROMORDWITHPAY,0)=0)
 EXECUTE LG_UPDATECLCARDRISKNUMS_099_02 @CLREF, @TRCODE, @NETTOTAL, 1, @REPORTRATE, @BILLED, 0, @STATUS, 0
IF (@AFFECTCOLLTRL=1) AND (ISNULL(@CANCELLED,0)=0)
 EXECUTE LG_UPDCOLLATRLRISK_099_02 @CLREF, @TRCODE, @NETTOTAL, 1, @REPORTRATE, @BILLED, 0, @STATUS, 0
